20	/** @file*/
21	
22	#include "internal_nn_math.h"
23	#include "riscv_nn_support.h"
24	
25	//// Convolution Functions
26	
27	int32_t riscv_nn_conv_1x1_HWC_u8_u8_s8_sym_bias_fast_any(const u8_t * in_tensor,
28	                                                const uint16_t in_tensor_dim_x,
29	                                                const uint16_t in_tensor_dim_y,
30	                                                const uint16_t in_tensor_ch,
31	                                                const q7_t * ker_weight,
32	                                                const uint16_t out_tensor_ch,
33	                                                const uint16_t ker_dim_x,
34	                                                const uint16_t ker_dim_y,
35	                                                const uint16_t pad_x,
36	                                                const uint16_t pad_y,
37	                                                const uint16_t stride_x,
38	                                                const uint16_t stride_y,
39	                                                const q31_t * bias,
40	                                                const uint16_t pre_rshift,
41	                                                const uint16_t out_scale,
42	                                                const uint16_t post_rshift,
43	                                                u8_t * out_tensor,
44	                                                const uint16_t out_tensor_dim_x,
45	                                                const uint16_t out_tensor_dim_y,
46	                                                q15_t * in_tmp_buf)
47	{
48	#ifdef ENA_EMPTY_FUN
49	    //empty body
50	#else
51	    if (in_tensor_ch % 4 != 0 || out_tensor_ch % 2 != 0 || ker_dim_x != 1 || ker_dim_y != 1
52	            || pad_x != 0 || pad_y != 0 || stride_x != 1 || stride_y != 1)
53	    {
54	        /* check if the input dimension meets the constraints */
55	        return -1;
56	    }
57	
58	#ifdef ENA_VEC_ISA
59	#if (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_TILING)
60	    //cache is 512KB, type is u8
61	    uint32_t tiling_size = 256;
62	    unsigned long addr_in_tmp_buf;
63	    u8_t *pOut = out_tensor;
64	    u8_t *src_buf = (u8_t *) in_tensor;
65	    q31_t *dst_q31;
66	
67	    const long align_byte = 64;
68	    addr_in_tmp_buf = (unsigned long)in_tmp_buf;
69	    addr_in_tmp_buf += sizeof(*ker_weight) * out_tensor_ch * in_tensor_ch;
70	    addr_in_tmp_buf = nn_align(addr_in_tmp_buf, align_byte);
71	    dst_q31 = (q31_t *)addr_in_tmp_buf;
72	
73	    //transpose the kernel_weight for matrix multiplication
74	    nn_mat_mul_kernel_tiling_transpose_q7(ker_weight, (q7_t *)in_tmp_buf, out_tensor_ch, in_tensor_ch);
75	
76	    pOut = nn_mat_mul_kernel_tiling_bias_u8_u8_s8(src_buf,
77	                                                  (q7_t *)in_tmp_buf,
78	                                                  dst_q31,
79	                                                  pOut,
80	                                                  in_tensor_dim_x * in_tensor_dim_y,
81	                                                  in_tensor_ch,
82	                                                  out_tensor_ch,
83	                                                  pre_rshift,
84	                                                  out_scale,
85	                                                  post_rshift,
86	                                                  bias,
87	                                                  tiling_size);
88	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100) && (ENA_VEC_INTRINSIC)
89	    unsigned long i_ch_out;
90	    u8_t *pOut = out_tensor;
91	    unsigned long vl;
92	
93	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
94	    u8_t *src_buf = (u8_t *)in_tensor;
95	    while(out_tensor_length-- > 0)
96	    {
97	        pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
98	                                                      src_buf,
99	                                                      out_tensor_ch,
100	                                                      in_tensor_ch,
101	                                                      pre_rshift,
102	                                                      out_scale,
103	                                                      post_rshift,
104	                                                      bias,
105	                                                      pOut);
106	        src_buf += 4 * in_tensor_ch;
107	    }
108	
109	    vl = __riscv_vsetvl_e32m1(1);
110	    vint32m1_t vZero = __riscv_vand(__riscv_vundefined_i32m1(), 0, vl);   //const zero for redsum
111	
112	    /* check if there is left-over for compute */
113	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
114	    while(rest-- > 0)
115	    {
116	        const q7_t *p_wt = ker_weight;
117	        const q31_t *bias2 = bias;
118	        uint16_t  colCnt = in_tensor_ch;
119	
120	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
121	        {
122	            u8_t  *p_in = src_buf;
123	            unsigned long colCnt2 = colCnt;
124	
125	            //clear v0~v7
126	            vl = __riscv_vsetvl_e32m8(colCnt);
127	            vint32m8_t vAccumulator = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
128	
129	            while(colCnt2 > 0)
130	            {
131	                vl = __riscv_vsetvl_e8m8(colCnt2);
132	                //load src1
133	                vint8m8_t vP_wt_i8m8 = __riscv_vle8_v_i8m8(p_wt, vl);
134	                //load src2
135	                vuint8m8_t vP_in_u8m8 = __riscv_vle8_v_u8m8(p_in, vl);
136	                //bump pointers and update loop counter
137	                colCnt2 -= vl;
138	                p_wt += vl;
139	                p_in += vl;
140	                //set the proper avl/SEW/LMUL values for vd4dot
141	                vl >>= 2;
142	                vl = __riscv_vsetvl_e32m8(vl);
143	                //acc += src1 * src2
144	                vAccumulator = __riscv_vd4dotsu_vv_i32m8(vAccumulator, vP_wt_i8m8, vP_in_u8m8, vl);
145	
146	            }
147	
148	            vl = __riscv_vsetvl_e32m8(colCnt);    //note the avl here
149	            vint32m1_t vSum = __riscv_vredsum(vAccumulator, vZero, vl);
150	
151	            //load bias
152	            vl = __riscv_vsetvl_e32m1(1);
153	            vint32m1_t vBias2 = __riscv_vle32_v_i32m1(bias2, vl);
154	            bias2 += vl;
155	
156	            //add bias to acc
157	            vSum = __riscv_vadd(vSum, vBias2, vl);
158	
159	            //2-stage shift
160	            vSum = __riscv_vsra(vSum, pre_rshift, vl);
161	            vSum = __riscv_vmul(vSum, out_scale, vl);
162	            vSum = __riscv_vadd(vSum, NN_ROUND(post_rshift), vl);
163	
164	            //saturate into 8-bits
165	            vSum = __riscv_vmax(vSum, 0, vl);
166	            vl = __riscv_vsetvl_e16mf2(1);     //1: 1 acc
167	            vint16mf2_t vSum_i16mf2 = __riscv_vnsra(vSum, post_rshift, vl);
168	            vl = __riscv_vsetvl_e8m1(1);      //1: 1 acc
169	            vuint16mf2_t vpOut_u16mf2 = __riscv_vreinterpret_u16mf2(vSum_i16mf2);
170	            vuint8mf4_t vpOut = __riscv_vnclipu(vpOut_u16mf2, 0, __RISCV_VXRM_RNU, vl);
171	
172	            //store the results
173	            // NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
174	            __riscv_vse8(pOut, vpOut, vl);
175	            pOut += vl;
176	        }
177	        src_buf += in_tensor_ch;
178	    }
179	#elif defined(ENA_NDS_V5_VEC_DOT_PROD) && (NDS_VEC_RVV_VERSION >= 100)
180	    unsigned long i_ch_out;
181	    u8_t *pOut = out_tensor;
182	    unsigned long vl;
183	
184	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
185	    u8_t *src_buf = (u8_t *)in_tensor;
186	    while(out_tensor_length-- > 0)
187	    {
188	        pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
189	                                                      src_buf,
190	                                                      out_tensor_ch,
191	                                                      in_tensor_ch,
192	                                                      pre_rshift,
193	                                                      out_scale,
194	                                                      post_rshift,
195	                                                      bias,
196	                                                      pOut);
197	        src_buf += 4 * in_tensor_ch;
198	    }
199	
200	    NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
201	    NDS_VEC_VAND_VI(NDS_VEC_V31, NDS_VEC_V31, 0);   //const zero for redsum
202	
203	    /* check if there is left-over for compute */
204	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
205	    while(rest-- > 0)
206	    {
207	        const q7_t *p_wt = ker_weight;
208	        const q31_t *bias2 = bias;
209	        uint16_t  colCnt = in_tensor_ch;
210	
211	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
212	        {
213	            u8_t  *p_in = src_buf;
214	            unsigned long colCnt2 = colCnt;
215	
216	            //clear v0~v7
217	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
218	            NDS_VEC_VAND_VI(NDS_VEC_V0, NDS_VEC_V0, 0x0);
219	
220	            while(colCnt2 > 0)
221	            {
222	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M8);
223	                //load src1
224	                NDS_VEC_VLB_V(NDS_VEC_V8, p_wt);
225	                //load src2
226	                NDS_VEC_VLB_V(NDS_VEC_V16, p_in);
227	                //bump pointers and update loop counter
228	                colCnt2 -= vl;
229	                p_wt += vl;
230	                p_in += vl;
231	                //set the proper avl/SEW/LMUL values for vd4dot
232	                vl >>= 2;
233	                NDS_VEC_VSETVLI(vl, vl, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);
234	                //acc += src1 * src2
235	                NDS_VEC_VD4DOTSU_VV(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V16);
236	            }
237	
238	            NDS_VEC_VSETVLI(vl, colCnt, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M8);    //note the avl here
239	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V31);
240	
241	            //load bias
242	            NDS_VEC_VSETVLI(vl, 1, NDS_VEC_VTYPE_SEW_E32, NDS_VEC_VTYPE_LMUL_M1);
243	            NDS_VEC_VLW_V(NDS_VEC_V30, bias2);
244	            bias2 += vl;
245	
246	            //add bias to acc
247	            NDS_VEC_VADD_VV(NDS_VEC_V0, NDS_VEC_V0, NDS_VEC_V30);
248	
249	            //2-stage shift
250	            NDS_VEC_VSRA_VX(NDS_VEC_V0, NDS_VEC_V0, pre_rshift);
251	            NDS_VEC_VMUL_VX(NDS_VEC_V0, NDS_VEC_V0, out_scale);
252	            NDS_VEC_VADD_VX(NDS_VEC_V0, NDS_VEC_V0, NN_ROUND(post_rshift));
253	
254	            //saturate into 8-bits
255	            NDS_VEC_VMAX_VX(NDS_VEC_V0, NDS_VEC_V0, 0);
256	            NDS_VEC_VSETVLI_E16(vl, 1);     //1: 1 acc
257	            NDS_VEC_VNSRA_WX(NDS_VEC_V0, NDS_VEC_V0, post_rshift);
258	            NDS_VEC_VSETVLI_E8(vl, 1);      //1: 1 acc
259	            NDS_VEC_VNCLIPU_WI(NDS_VEC_V0, NDS_VEC_V0, 0);
260	
261	            //store the results
262	            NDS_VEC_VSB_V(NDS_VEC_V0, pOut);
263	            pOut += vl;
264	        }
265	        src_buf += in_tensor_ch;
266	    }
267	#elif (NDS_VEC_RVV_VERSION >= 100) && defined(ENA_VEC_INTRINSIC)
268	    unsigned long i_ch_out;
269	    u8_t *pOut = out_tensor;
270	    unsigned long vl;
271	
272	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
273	    u8_t *src_buf = (u8_t *)in_tensor;
274	    while(out_tensor_length-- > 0)
275	    {
276	        pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
277	                                                      src_buf,
278	                                                      out_tensor_ch,
279	                                                      in_tensor_ch,
280	                                                      pre_rshift,
281	                                                      out_scale,
282	                                                      post_rshift,
283	                                                      bias,
284	                                                      pOut);
285	        src_buf += 4 * in_tensor_ch;
286	    }
287	
288	    /* check if there is left-over for compute */
289	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
290	    while(rest-- > 0)
291	    {
292	        const q7_t *pA = ker_weight;
293	        uint16_t  colCnt = in_tensor_ch;
294	
295	        //set SEW for 1st time VMV_S_X
296	        //LMUL=8 is just for clear v16~v23 (vmv ignores LMUL)
297	        vl = __riscv_vsetvl_e32m8(colCnt);
298	
299	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
300	        {
301	            q31_t sum = bias[i_ch_out];
302	            u8_t  *pB = src_buf;
303	            unsigned long colCnt2 = colCnt;
304	
305	            //init
306	            vint32m1_t vSum = __riscv_vmv_s_x_i32m1(sum, 1);
307	            //clear v16~v23
308	            vint32m8_t vAcc = __riscv_vand(__riscv_vundefined_i32m8(), 0x0, vl);
309	
310	            while(colCnt2 > 0)
311	            {
312	                vl = __riscv_vsetvl_e8m2(colCnt2);
313	                //load src1
314	                vint8m2_t vpA = __riscv_vle8_v_i8m2(pA, vl);
315	                //load src2
316	                vuint8m2_t vpB = __riscv_vle8_v_u8m2(pB, vl);
317	                //acc += src1 * src2
318	                vAcc = __riscv_vqmaccsu(vAcc, vpA, vpB, vl);
319	                //bump pointers and update loop counter
320	                colCnt2 -= vl;
321	                pA += vl;
322	                pB += vl;
323	            }
324	
325	            vl = __riscv_vsetvl_e32m8(colCnt);     //note the avl here
326	            vSum = __riscv_vredsum_tu(vSum, vAcc, vSum, vl);
327	            //move vr results to gpr
328	            sum = __riscv_vmv_x(vSum);
329	
330	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
331	            *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
332	        }
333	        src_buf += in_tensor_ch;
334	    }
335	#elif (NDS_VEC_RVV_VERSION >= 100)
336	    unsigned long i_ch_out;
337	    u8_t *pOut = out_tensor;
338	    unsigned long vl;
339	
340	    unsigned long out_tensor_length = (out_tensor_dim_y * out_tensor_dim_x) >> 2;   //ignore in_ch
341	    u8_t *src_buf = (u8_t *)in_tensor;
342	    while(out_tensor_length-- > 0)
343	    {
344	        pOut = nn_mat_mul_kernel_u8_bias_2sft_unroll4(ker_weight,
345	                                                      src_buf,
346	                                                      out_tensor_ch,
347	                                                      in_tensor_ch,
348	                                                      pre_rshift,
349	                                                      out_scale,
350	                                                      post_rshift,
351	                                                      bias,
352	                                                      pOut);
353	        src_buf += 4 * in_tensor_ch;
354	    }
355	
356	    /* check if there is left-over for compute */
357	    long rest = (out_tensor_dim_y * out_tensor_dim_x) & 0x3;
358	    while(rest-- > 0)
359	    {
360	        const q7_t *pA = ker_weight;
361	        uint16_t  colCnt = in_tensor_ch;
362	
363	        //set SEW for 1st time VMV_S_X
364	        //LMUL=8 is just for clear v16~v23 (vmv ignores LMUL)
365	        NDS_VEC_VSETVLI_E32_M8(vl, colCnt);
366	
367	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
368	        {
369	            q31_t sum = bias[i_ch_out];
370	            u8_t  *pB = src_buf;
371	            unsigned long colCnt2 = colCnt;
372	
373	            //init
374	            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
375	            //clear v16~v23
376	            NDS_VEC_VAND_VI(NDS_VEC_V8, NDS_VEC_V8, 0x0);
377	
378	            while(colCnt2 > 0)
379	            {
380	                NDS_VEC_VSETVLI(vl, colCnt2, NDS_VEC_VTYPE_SEW_E8, NDS_VEC_VTYPE_LMUL_M2);
381	                //load src1
382	                NDS_VEC_VLB_V(NDS_VEC_V2, pA);
383	                //load src2
384	                NDS_VEC_VLB_V(NDS_VEC_V4, pB);
385	                //acc += src1 * src2
386	                NDS_VEC_VQMACCSU_VV(NDS_VEC_V8, NDS_VEC_V2, NDS_VEC_V4);
387	                //bump pointers and update loop counter
388	                colCnt2 -= vl;
389	                pA += vl;
390	                pB += vl;
391	            }
392	
393	            NDS_VEC_VSETVLI_E32_M8(vl, colCnt);     //note the avl here
394	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V8, NDS_VEC_V0);
395	            //move vr results to gpr
396	            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
397	
398	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
399	            *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
400	        }
401	        src_buf += in_tensor_ch;
402	    }
403	#else
404	    unsigned long   i_out_y, i_out_x;
405	    unsigned long   i_ch_out;
406	
407	    /* -----------------------
408	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
409	     *  im2col are done to output in q15_t format from q7_t input
410	     */
411	
412	    u8_t    *pBuffer = (u8_t *)in_tmp_buf;
413	    u8_t     *pOut = out_tensor;
414	
415	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
416	    {
417	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
418	        {
419	            /* This part implements the im2col function */
420	            //riscv_nn_dup_s8_s8
421	            int32_t vl;
422	            uint16_t copy_len = in_tensor_ch;
423	            u8_t *src_buf = (u8_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch;
424	            while(copy_len > 0)
425	            {
426	                NDS_VEC_VSETVLI_E8(vl, copy_len);
427	                NDS_VEC_VLB_V(NDS_VEC_V0, src_buf);
428	                NDS_VEC_VSB_V(NDS_VEC_V0, pBuffer);
429	                src_buf += vl;
430	                pBuffer += vl;
431	                copy_len -= vl;
432	            }
433	
434	            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
435	            {
436	                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
437	                                                      (u8_t *)in_tmp_buf,
438	                                                      out_tensor_ch,
439	                                                      in_tensor_ch,
440	                                                      pre_rshift,
441	                                                      out_scale,
442	                                                      post_rshift,
443	                                                      bias,
444	                                                      pOut);
445	                /* counter reset */
446	                pBuffer = (u8_t*)in_tmp_buf;
447	            }
448	        }
449	    }
450	
451	    /* check if there is left-over for compute */
452	    if (pBuffer != (u8_t*)in_tmp_buf)
453	    {
454	        int32_t vl;
455	        const q7_t *pA = ker_weight;
456	        uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
457	
458	        //set SEW for 1st time VMV_S_X
459	        //LMUL=2 is just for clear v2~v3 (vmv ignores LMUL)
460	        NDS_VEC_VSETVLI_E32_M2(vl, colCnt);
461	
462	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
463	        {
464	            q31_t     sum = bias[i_ch_out];
465	            u8_t      *pB = (u8_t*)in_tmp_buf;
466	            uint16_t colCnt2 = colCnt;
467	
468	            //init
469	            NDS_VEC_VMV_S_X(NDS_VEC_V0, sum);
470	            //clear v2~v3
471	            NDS_VEC_VAND_VI(NDS_VEC_V2, NDS_VEC_V2, 0x0);
472	
473	            while(colCnt2 > 0)
474	            {
475	                NDS_VEC_VSETVLI_E16(vl, colCnt2);
476	                //load src1
477	                NDS_VEC_VLB_V(NDS_VEC_V1, pA);
478	                //load src2
479	                NDS_VEC_VLBU_V(NDS_VEC_V4, pB);
480	                //acc += src1 * src2
481	                NDS_VEC_VWMACC_VV(NDS_VEC_V2, NDS_VEC_V4, NDS_VEC_V1);
482	                //bump pointers and update loop counter
483	                colCnt2 -= vl;
484	                pA += vl;
485	                pB += vl;
486	            }
487	
488	            NDS_VEC_VSETVLI_E32_M2(vl, colCnt);     //note the avl here
489	            NDS_VEC_VREDSUM_VS(NDS_VEC_V0, NDS_VEC_V2, NDS_VEC_V0);
490	            //move vr results to gpr
491	            NDS_VEC_VMV_X_S(sum, NDS_VEC_V0);
492	
493	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
494	            *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
495	        }
496	    }
497	#endif
498	#elif defined(ENA_DSP_ISA_V5)
499	    unsigned long   i_out_y, i_out_x;
500	    unsigned long   i_ch_out;
501	
502	    u8_t    *pBuffer = (u8_t *)in_tmp_buf;
503	    u8_t     *pOut = out_tensor;
504	
505	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
506	    {
507	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
508	        {
509	            /* This part implements the im2col function */
510	            nn_dup_u8((u8_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch, pBuffer, in_tensor_ch);
511	            pBuffer += in_tensor_ch;
512	
513	            if (pBuffer == (u8_t *)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
514	            {
515	                pOut = nn_mat_mul_kernel_u8_bias_2sft(ker_weight,
516	                                                      (u8_t *)in_tmp_buf,
517	                                                      out_tensor_ch,
518	                                                      in_tensor_ch,
519	                                                      pre_rshift,
520	                                                      out_scale,
521	                                                      post_rshift,
522	                                                      bias,
523	                                                      pOut);
524	                /* counter reset */
525	                pBuffer = (u8_t*)in_tmp_buf;
526	            }
527	        }
528	    }
529	#ifdef ENA_DSP_ISA_64 //V5 64, DX25
530	    if (pBuffer != (u8_t*)in_tmp_buf)
531	    {
532	        const q7_t *pA = ker_weight;
533	
534	        uint16_t colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
535	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
536	        {
537	            q63_t     sum = 0;
538	            u8_t      *pB = (u8_t*)in_tmp_buf;
539	            uint16_t colCnt2 = colCnt >> 3;
540	
541	            while(colCnt2)
542	            {
543	                q63_t inA1 = *__SIMD64(pA)++;
544	                u64_t inB1 = *__SIMD64(pB)++;
545	                sum = NDS_DSP_SMAQA_SU(sum, inA1, inB1);
546	                colCnt2--;
547	            }
548	
549	            //sum up the high and low part results (SIMD results)
550	            sum = PADD_S32(sum);
551	
552	            colCnt2 = colCnt & 0x7;
553	            while (colCnt2)
554	            {
555	                q7_t	inA1 = *pA++;
556	                u8_t	inB1 = *pB++;
557	                sum += inA1 * inB1;
558	                colCnt2--;
559	            }
560	
561	            sum += bias[i_ch_out];
562	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
563	            *pOut++ = NDS_DSP_SAT((sum >> post_rshift), 8);
564	        }
565		}
566	#else //V5 32, D25
567	    if (pBuffer != (u8_t*)in_tmp_buf)
568	    {
569	        const q7_t *pA = ker_weight;
570	
571	        uint16_t colCnt = in_tensor_ch * ker_dim_x * ker_dim_y;
572	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
573	        {
574	            q31_t     sum = bias[i_ch_out];;
575	            u8_t      *pB = (u8_t*)in_tmp_buf;
576	            uint16_t colCnt2 = colCnt >> 2;
577	
578	            while(colCnt2)
579	            {
580	                q31_t inA1 = *__SIMD32(pA)++;
581	                u32_t inB1 = *__SIMD32(pB)++;
582	                sum = NDS_DSP_SMAQA_SU(sum, inA1, inB1);
583	                colCnt2--;
584	            }
585	
586	            //since in_tensor_ch is multiple of 4 (input constraints), the
587	            //following codes will not be reached
588	            // colCnt2 = colCnt & 0x3;
589	            // while (colCnt2)
590	            // {
591	            //     q7_t    inA1 = *pA++;
592	            //     u8_t    inB1 = *pB++;
593	            //     sum += inA1 * inB1;
594	            //     colCnt2--;
595	            // }
596	
597	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
598	            *pOut++ = NDS_ISA_SAT((sum >> post_rshift), 8);
599	        }
600	    }
601	#endif
602	#elif defined(ENA_DSP_ISA)
603	    unsigned long   i_out_y, i_out_x;
604	    unsigned long   i_ch_out;
605	
606	    /* -----------------------
607	     *  Here we use in_tmp_buf as q15_t internally as computation are done with q15_t level
608	     *  im2col are done to output in q15_t format from q7_t input
609	     */
610	
611	    u16_t    *pBuffer = (u16_t*)in_tmp_buf;
612	    u8_t     *pOut = out_tensor;
613	
614	    for (i_out_y = 0; i_out_y < out_tensor_dim_y; i_out_y++)
615	    {
616	        for (i_out_x = 0; i_out_x < out_tensor_dim_x; i_out_x++)
617	        {
618	            /* This part implements the im2col function */
619	            nn_dup_u8_u16_reordered((u8_t *) in_tensor + (i_out_y * in_tensor_dim_x + i_out_x) * in_tensor_ch,
620	                                        pBuffer, in_tensor_ch);
621	            pBuffer += in_tensor_ch;
622	
623	            if (pBuffer == (u16_t*)in_tmp_buf + 2 * in_tensor_ch * ker_dim_x * ker_dim_y)
624	            {
625	                pOut = nn_mat_mul_kernel_q7_u16_u8_reordered_bias_2sft(ker_weight,
626	                                                                       (u16_t*)in_tmp_buf,
627	                                                                       out_tensor_ch,
628	                                                                       in_tensor_ch,
629	                                                                       pre_rshift,
630	                                                                       out_scale,
631	                                                                       post_rshift,
632	                                                                       bias,
633	                                                                       pOut);
634	                /* counter reset */
635	                pBuffer = (u16_t*)in_tmp_buf;
636	            }
637	        }
638	    }
639	
640	    /* check if there is left-over for compute */
641	    if (pBuffer != (u16_t*)in_tmp_buf)
642	    {
643	        const q7_t *pA = ker_weight;
644	        for (i_ch_out = 0; i_ch_out < out_tensor_ch; i_ch_out++)
645	        {
646	            q31_t     sum = bias[i_ch_out];
647	            u16_t    *pB = (u16_t*)in_tmp_buf;
648	
649	            /* basically each time it process 4 entries */
650	            uint16_t  colCnt = in_tensor_ch * ker_dim_x * ker_dim_y >> 2;
651	
652	            while (colCnt)
653	            {
654	                q31_t     inA1, inA2;
655	                q31_t     inB1, inB2;
656	
657	                pA = (const q7_t *)read_and_pad_reordered((void *)pA, &inA1, &inA2);
658	                inB1 = *__SIMD32(pB)++;
659	                sum = NDS_DSP_KMADA(sum, inA1, inB1);
660	                inB2 = *__SIMD32(pB)++;
661	                sum = NDS_DSP_KMADA(sum, inA2, inB2);
662	                colCnt--;
663	            }
664	
665	            //since in_tensor_ch is multiple of 4 (input constraints), the
666	            //following codes will not be reached
667	            // colCnt = in_tensor_ch * ker_dim_y * ker_dim_x & 0x3;
668	            // while (colCnt)
669	            // {
670	            //     q7_t      inA1 = *pA++;
671	            //     q15_t     inB1 = *pB++;
672	            //     sum += inA1 * inB1;
673	            //     colCnt--;
674	            // }
675	            sum = (sum >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
676	            *pOut = NDS_DSP_SAT((sum >> post_rshift), 8);
677	            pOut++;
678	        }
679	    }
680	#else // general
681	    int       i, j, k, l, m, n;
682	    int       conv_out;
683	    int       in_row, in_col;
684	
685	    for (i = 0; i < out_tensor_ch; i++)
686	    {
687	        for (j = 0; j < out_tensor_dim_y; j++)
688	        {
689	            for (k = 0; k < out_tensor_dim_x; k++)
690	            {
691	                conv_out = bias[i];
692	                for (m = 0; m < ker_dim_y; m++)
693	                {
694	                    for (n = 0; n < ker_dim_x; n++)
695	                    {
696	                        // if-for implementation
697	                        in_row = stride_y * j + m - pad_y;
698	                        in_col = stride_x * k + n - pad_x;
699	                        if (in_row >= 0 && in_col >= 0 && in_row < in_tensor_dim_y && in_col < in_tensor_dim_x)
700	                        {
701	                            for (l = 0; l < in_tensor_ch; l++)
702	                            {
703	                                conv_out += in_tensor[(in_row * in_tensor_dim_x + in_col) * in_tensor_ch + l] *
704	                                            ker_weight[i * in_tensor_ch * ker_dim_y * ker_dim_x + (m * ker_dim_y + n) * in_tensor_ch + l];
705	                            }
706	                        }
707	                    }
708	                }
709	                if(conv_out < 0)
710	                    out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = 0;
711	                else
712	                {
713	                    conv_out = (conv_out >> pre_rshift) * out_scale + NN_ROUND(post_rshift);
714	                    out_tensor[i + (j * out_tensor_dim_x + k) * out_tensor_ch] = NDS_ISA_SAT((conv_out >> post_rshift), 8);
715	                }
716	            }
717	        }
718	    }
719	#endif
720	#endif  //ENA_EMPTY_FUN
721	
722	    /* Return to application */
723	    return 0;
724	}
