672	            for (long i_output_y = 0; i_output_y < out_tensor_dim_y; i_output_y++)
673	            {
674	                // Process one input row
675	                nn_mat_mult_nt_t_s8_v2(in_tensor2,
676	                                       ker_weight,
677	                                       bias,
678	                                       out_tensor,
679	                                       out_scale,
680	                                       out_shift,
681	                                       lhs_rows,
682	                                       rhs_rows,
683	                                       rhs_cols,
684	                                       in_offset,
685	                                       out_offset,
686	                                       act_min,
687	                                       act_max,
688	                                       lhs_cols_offset,
689	                                       contri_buf);
690	                in_tensor2 += input_inc;
691	                out_tensor += output_inc;
692	            }
693	        }
694	    }
695	#elif defined(ENA_DSP_ISA)
696	    if ((pad_x != 0) ||
697	        (pad_y != 0))
698	    {
699	        return -1;
700	    }
701	
702	    (void)tmp_buf;
703	
704	    // calculate the weight contribution
705	    int32_t contri_buf[out_tensor_ch];
706	    const int8_t *pWt = ker_weight;
707	    const long cst_one = 0x01010101;
708	    for (long cur_out_ch = 0; cur_out_ch < out_tensor_ch; cur_out_ch++)
709	    {
710	        long sum = 0;
711	        long in_tensor_ch2 = in_tensor_ch;
712	        while (in_tensor_ch2 >= SIMD_NUM_Q7)
713	        {
714	            suni_t wt_val = simd_load_8((s8_t*)pWt, 0);
715	            sum = NDS_DSP_SMAQA(sum, wt_val.l0, cst_one);
716	            pWt += SIMD_NUM_Q7;
717	            in_tensor_ch2 -= SIMD_NUM_Q7;
718	        }
719	
720	        // rest loop
721	        while (in_tensor_ch2 > 0)
722	        {
723	            sum += *pWt;
724	            pWt++;
725	            in_tensor_ch2--;
726	        }
727	
728	        // add in_offset contribution back
729	        sum *= in_offset;
730	
731	        if (bias != NULL)
732	        {
733	            sum += bias[cur_out_ch];
734	        }
735	
736	        contri_buf[cur_out_ch] = sum;
737	    }
738	
739	    if ((stride_x == 1) && (stride_y == 1))
740	    {
741	        const long lhs_rows = in_tensor_dim_x * in_tensor_dim_y * in_tensor_batch;
742	        const long rhs_rows = out_tensor_ch;
743	        const long rhs_cols = in_tensor_ch;
744	        const long lhs_cols_offset = rhs_cols;
