746	        nn_mat_mult_nt_t_s8_v2(in_tensor,
747	                               ker_weight,
748	                               bias,
749	                               out_tensor,
750	                               out_scale,
751	                               out_shift,
752	                               lhs_rows,
753	                               rhs_rows,
754	                               rhs_cols,
755	                               in_offset,
756	                               out_offset,
757	                               act_min,
758	                               act_max,
759	                               lhs_cols_offset,
760	                               contri_buf);
761	    }
762	    else
763	    {
764	        const long lhs_rows = out_tensor_dim_x;
765	        const long rhs_rows = out_tensor_ch;
766	        const long rhs_cols = in_tensor_ch;
767	        const long input_inc = in_tensor_dim_x * stride_y * rhs_cols;
768	        const long output_inc = out_tensor_dim_x * rhs_rows;
769	        const long lhs_cols_offset = rhs_cols * stride_x;
770	
771	        for (long i_batch = 0; i_batch < in_tensor_batch; i_batch++)
772	        {
773	            const int8_t *in_tensor2 = in_tensor + (i_batch * in_tensor_dim_y * in_tensor_dim_x * in_tensor_ch);
774	            for (long i_output_y = 0; i_output_y < out_tensor_dim_y; i_output_y++)
775	            {
776	                // Process one input row
777	                nn_mat_mult_nt_t_s8_v2(in_tensor2,
778	                                       ker_weight,
779	                                       bias,
780	                                       out_tensor,
781	                                       out_scale,
782	                                       out_shift,
783	                                       lhs_rows,
784	                                       rhs_rows,
785	                                       rhs_cols,
786	                                       in_offset,
787	                                       out_offset,
788	                                       act_min,
789	                                       act_max,
790	                                       lhs_cols_offset,
791	                                       contri_buf);
792	                in_tensor2 += input_inc;
793	                out_tensor += output_inc;
794	            }
795	        }
796	    }
797	#else
798	    if ((pad_x != 0) ||
799	        (pad_y != 0))
800	    {
801	        return -1;
802	    }
803	
804	    (void)tmp_buf;
805	
806	    if ((stride_x == 1) && (stride_y == 1))
807	    {
808	        const int32_t lhs_rows = in_tensor_dim_x * in_tensor_dim_y * in_tensor_batch;
809	        const int32_t rhs_rows = out_tensor_ch;
810	        const int32_t rhs_cols = in_tensor_ch;
811	        const int32_t lhs_cols_offset = rhs_cols;
812	
813	        nn_mat_mult_nt_t_s8(in_tensor,
814	                            ker_weight,
815	                            bias,
816	                            out_tensor,
817	                            out_scale,
818	                            out_shift,
819	                            lhs_rows,
820	                            rhs_rows,
821	                            rhs_cols,
822	                            in_offset,
823	                            out_offset,
824	                            act_min,
825	                            act_max,
826	                            lhs_cols_offset);
827	    }
828	    else
829	    {
830	        const int32_t lhs_rows = out_tensor_dim_x;
831	        const int32_t rhs_rows = out_tensor_ch;
832	        const int32_t rhs_cols = in_tensor_ch;
833	        const int32_t input_inc = in_tensor_dim_x * stride_y * rhs_cols;
834	        const int32_t output_inc = out_tensor_dim_x * rhs_rows;
835	        const int32_t lhs_cols_offset = rhs_cols * stride_x;
