837	        for (int i_batch = 0; i_batch < in_tensor_batch; i_batch++)
838	        {
839	            const int8_t *in_tensor2 = in_tensor + (i_batch * in_tensor_dim_y * in_tensor_dim_x * in_tensor_ch);
840	            for (int i_output_y = 0; i_output_y < out_tensor_dim_y; i_output_y++)
