887	    uint32_t buf_A = 0, buf_B = 0, buf_C = 0;
888	    const long align_byte = 64;
889	    uint32_t tiling_size = 256;
890	#ifdef DCACHE_SIZE
891	    int i;
892	    int tiling_size_arr[] = { 1,8,16,32,64,128,256,512,1024,2048 };
893	    int max_tile_size_in_cache = sqrt(((DCACHE_SIZE) << 10) / (6 * sizeof(int8_t)));
894	    for (i = 1; i < sizeof(tiling_size_arr) / sizeof(tiling_size_arr[0]); i++)
895	    {
896	        if (tiling_size_arr[i] > max_tile_size_in_cache)
897	        {
898	            tiling_size = tiling_size_arr[i - 1];
899	            break;
900	        }
901	    }
902	#endif
903	    if ((stride_x == 1) && (stride_y == 1))
904	    {
